const data = $input.first().json;
const messages = (data.value || []).sort((a, b) => new Date(a.receivedDateTime) - new Date(b.receivedDateTime));

const cleaned = messages.map(m => {
  const rawHtml = m.body?.content || '';

  // Strip Outlook reply divider and everything after it
  let strippedHtml = rawHtml;
  const divIdx = strippedHtml.search(/<div[^>]*id="divRplyFwdMsg"/i);
  if (divIdx > -1) strippedHtml = strippedHtml.slice(0, divIdx);

  // Remove blockquotes (Gmail/Outlook quoted text) and boilerplate tags
  strippedHtml = strippedHtml
    .replace(/<blockquote[\s\S]*?<\/blockquote>/gi, '')
    .replace(/<head[\s\S]*?<\/head>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .slice(0, 40000);

  const bodyText = strippedHtml.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 3000);

  const to = (m.toRecipients || []).map(r => {
    const name = r.emailAddress?.name || '';
    const addr = r.emailAddress?.address || '';
    return name && name !== addr ? name + ' <' + addr + '>' : addr;
  }).filter(Boolean).join(', ');

  const cc = (m.ccRecipients || []).map(r => {
    const name = r.emailAddress?.name || '';
    const addr = r.emailAddress?.address || '';
    return name && name !== addr ? name + ' <' + addr + '>' : addr;
  }).filter(Boolean).join(', ');

  return {
    id: m.id,
    subject: m.subject || '',
    from: m.from?.emailAddress?.address || '',
    fromName: m.from?.emailAddress?.name || '',
    to,
    cc,
    receivedAt: m.receivedDateTime || '',
    isRead: m.isRead || false,
    hasAttachments: m.hasAttachments || false,
    conversationId: m.conversationId || '',
    bodyHtml: strippedHtml,
    body: bodyText
  };
});

return [{ json: { messages: cleaned, count: cleaned.length } }];
